// Import from '@/stores'
export interface TimerStoreState {
  activeTimer: ActiveTimer | null;
  localElapsed: number;
  isRunning: boolean;
  offlineQueue: QueuedAction[];
  setActiveTimer: (timer: ActiveTimer | null) => void;
  startLocalTick: () => void;
  stopLocalTick: () => void;
  queueAction: (action: QueuedAction) => void;
  clearQueue: () => void;
  syncFromServer: (timer: ActiveTimer | null) => void;
}

export declare function getTimerStoreState(): TimerStoreState;
export declare function subscribeTimerStore(listener: () => void): () => void;
export declare function useTimerStore<T>(selector: (state: TimerStoreState) => T): T;

// Behavior notes:
// - localElapsed is computed from UTC server timestamp: floor((Date.now() - Date.parse(started_at))/1000)
// - offlineQueue is persisted and hydrated from storage key `worktracker.timer-store.v1`
// - startLocalTick/stopLocalTick manage a 1-second interval for elapsed updates
